"use client";
import { useParams } from "next/navigation";
import React, { useEffect, useState } from "react";

// ✅ Safe date formatter
const formatDate = (dateStr) => {
  const d = new Date(dateStr);
  const day = d.getDate().toString().padStart(2, "0");
  const month = (d.getMonth() + 1).toString().padStart(2, "0");
  const year = d.getFullYear();
  return `${day}/${month}/${year}`;
};

export default function UserDashboard() {
  const { details } = useParams();
  const [subscriptionTab, setSubscriptionTab] = useState("current");
  const [serviceTab, setServiceTab] = useState("current");

  const [user, setUser] = useState({
    name: "Kush Qurilo",
    email: "kush@example.com",
    // Subscriptions
    paidSubscriptions: [
      {
        paidForMonth: "October 2025",
        paidForDueDate: "2025-10-31",
        amount: 1000,
        gst: 18,
        totalAmount: 1180,
        status: "paid",
      },
      {
        paidForMonth: "September 2025",
        paidForDueDate: "2025-09-30",
        amount: 1500,
        gst: 18,
        totalAmount: 1770,
        status: "paid",
      },
    ],
    unpaidSubscriptions: [
      {
        paidForMonth: "November 2025",
        paidForDueDate: "2025-11-30",
        amount: 1200,
        gst: 18,
        totalAmount: 1416,
        status: "pending",
      },
    ],
    // Services
    paidServices: [
      {
        paidForMonth: "October 2025",
        emiNumber: 1,
        emiAmount: 299,
        dueDate: "2025-10-25",
        status: "paid",
      },
      {
        paidForMonth: "September 2025",
        emiNumber: 2,
        emiAmount: 199,
        dueDate: "2025-10-20",
        status: "paid",
      },
    ],
    unpaidServices: [
      {
        paidForMonth: "November 2025",
        emiNumber: 1,
        emiAmount: 250,
        dueDate: "2025-11-30",
        status: "pending",
      },
      {
        paidForMonth: "December 2025",
        emiNumber: 1,
        emiAmount: 300,
        dueDate: "2025-12-15",
        status: "pending",
      },
    ],
  });

  const subscriptionsToShow =
    subscriptionTab === "paid"
      ? user.paidSubscriptions
      : user.unpaidSubscriptions;
  const servicesToShow =
    serviceTab === "paid" ? user.paidServices : user.unpaidServices;

  // ✅ Status badge class
  const getStatusClass = (status) => {
    if (status === "paid") return "bg-green-100 text-green-600";
    if (status === "pending") return "bg-yellow-100 text-yellow-600";
    return "bg-gray-200 text-gray-500";
  };

  // ✅ Check payment API for pending subscriptions
  const checkPayment = async (subIndex) => {
    try {
      const res = await fetch(
        `/api/checkPayment?month=${user.unpaidSubscriptions[subIndex].paidForMonth}`
      );
      const data = await res.json();

      if (data.status === "paid") {
        const updatedPaid = [
          ...user.paidSubscriptions,
          { ...user.unpaidSubscriptions[subIndex], status: "paid" },
        ];
        const updatedUnpaid = user.unpaidSubscriptions.filter(
          (_, idx) => idx !== subIndex
        );
        setUser({
          ...user,
          paidSubscriptions: updatedPaid,
          unpaidSubscriptions: updatedUnpaid,
        });
        alert(`Subscription for ${data.paidForMonth} is now PAID.`);
      } else {
        alert(
          `Subscription for ${user.unpaidSubscriptions[subIndex].paidForMonth} is still PENDING.`
        );
      }
    } catch (err) {
      console.error(err);
      alert("Error checking payment. Try again.");
    }
  };

  // ✅ Mark subscription as paid manually
  const markAsPaid = (subIndex) => {
    const updatedPaid = [
      ...user.paidSubscriptions,
      { ...user.unpaidSubscriptions[subIndex], status: "paid" },
    ];
    const updatedUnpaid = user.unpaidSubscriptions.filter(
      (_, idx) => idx !== subIndex
    );
    setUser({
      ...user,
      paidSubscriptions: updatedPaid,
      unpaidSubscriptions: updatedUnpaid,
    });
    alert(
      `Subscription for ${user.unpaidSubscriptions[subIndex].paidForMonth} marked as PAID.`
    );
  };

  // ✅ Mark service as paid manually
  const checkServicePayment = (svcIndex) => {
    const updatedPaid = [
      ...user.paidServices,
      { ...user.unpaidServices[svcIndex], status: "paid" },
    ];
    const updatedUnpaid = user.unpaidServices.filter(
      (_, idx) => idx !== svcIndex
    );
    setUser({
      ...user,
      paidServices: updatedPaid,
      unpaidServices: updatedUnpaid,
    });
    alert(
      `Service for ${user.unpaidServices[svcIndex].paidForMonth} marked as PAID.`
    );
  };

  useEffect(() => {});
  return (
    <div className="max-w-4xl mx-auto p-6 bg-white rounded-2xl shadow-md space-y-8">
      {/* 👤 User Info */}
      <div className="border-b pb-4">
        <h2 className="text-2xl font-bold text-gray-800">{user.name}</h2>
        <p className="text-gray-500">{user.email}</p>
      </div>

      {/* 💳 Subscriptions Section */}
      <div className="space-y-3">
        <h3 className="text-xl font-semibold text-gray-800">
          Monthly Subscriptions
        </h3>
        {/* Tabs */}
        <ul className="flex border-b mb-3">
          <li
            className={`cursor-pointer px-4 py-2 ${
              subscriptionTab === "current"
                ? "border-b-2 border-blue-600 font-semibold text-blue-600"
                : "text-gray-500 hover:text-blue-600"
            }`}
            onClick={() => setSubscriptionTab("current")}
          >
            Current
          </li>
          <li
            className={`cursor-pointer px-4 py-2 ${
              subscriptionTab === "paid"
                ? "border-b-2 border-blue-600 font-semibold text-blue-600"
                : "text-gray-500 hover:text-blue-600"
            }`}
            onClick={() => setSubscriptionTab("paid")}
          >
            Paid
          </li>
        </ul>

        {/* Subscription List */}
        <div className="max-h-96 overflow-y-auto space-y-3 pr-2 border rounded-xl p-4 bg-gray-50">
          {subscriptionsToShow.length === 0 ? (
            <p className="text-gray-500 text-sm">No subscriptions found.</p>
          ) : (
            subscriptionsToShow.map((sub, index) => (
              <div
                key={index}
                className="p-4 border rounded-xl bg-white hover:bg-gray-100 transition relative"
              >
                {/* Status badge */}
                <span
                  className={`absolute top-4 right-4 text-sm font-medium px-3 py-1 rounded-full ${getStatusClass(
                    sub.status
                  )}`}
                >
                  {sub.status.toUpperCase()}
                </span>

                {/* Subscription info */}
                <div>
                  <p className="font-semibold text-gray-800">
                    {sub.paidForMonth}
                  </p>
                  <p className="text-sm text-gray-500">
                    Due Date: {formatDate(sub.paidForDueDate)}
                  </p>
                </div>
                <div className="mt-2 grid grid-cols-2 md:grid-cols-3 gap-2 text-sm text-gray-700">
                  <p>Amount: ₹{sub.amount}</p>
                  <p>GST :{sub.gst}%</p>
                  <p>Total: ₹{sub.totalAmount}</p>
                </div>

                {/* ✅ Mark as Paid button for pending */}
                {sub.status === "pending" && (
                  <button
                    onClick={() => markAsPaid(index)}
                    className="absolute bottom-4 right-4 px-3 py-1 bg-blue-600 text-white rounded hover:bg-green-700 transition text-sm"
                  >
                    Mark as Paid
                  </button>
                )}
              </div>
            ))
          )}
        </div>
      </div>

      {/* 🧰 Services Section */}
      <div className="space-y-3">
        <h3 className="text-xl font-semibold mb-3 text-gray-800">Services</h3>
        {/* Tabs */}
        <ul className="flex border-b mb-3">
          <li
            className={`cursor-pointer px-4 py-2 ${
              serviceTab === "current"
                ? "border-b-2 border-blue-600 font-semibold text-blue-600"
                : "text-gray-500 hover:text-blue-600"
            }`}
            onClick={() => setServiceTab("current")}
          >
            Current
          </li>
          <li
            className={`cursor-pointer px-4 py-2 ${
              serviceTab === "paid"
                ? "border-b-2 border-blue-600 font-semibold text-blue-600"
                : "text-gray-500 hover:text-blue-600"
            }`}
            onClick={() => setServiceTab("paid")}
          >
            Paid
          </li>
        </ul>

        {/* Service List */}
        <div className="max-h-96 overflow-y-auto space-y-3 pr-2 border rounded-xl p-4 bg-gray-50">
          {servicesToShow.length === 0 ? (
            <p className="text-gray-500 text-sm">No services found.</p>
          ) : (
            servicesToShow.map((service, index) => (
              <div
                key={index}
                className="p-4 border rounded-xl bg-white hover:bg-gray-100 transition relative"
              >
                {/* Status badge */}
                <span
                  className={`absolute top-4 right-4 text-sm font-medium px-3 py-1 rounded-full ${getStatusClass(
                    service.status
                  )}`}
                >
                  {service.status.toUpperCase()}
                </span>

                {/* Service info */}
                <div>
                  <p className="font-semibold text-gray-800">
                    {service.paidForMonth}
                  </p>
                  <p className="text-sm text-gray-500">
                    EMI Number: {service.emiNumber}
                  </p>
                </div>
                <div className="mt-2 grid grid-cols-2 md:grid-cols-3 gap-2 text-sm text-gray-700">
                  <p>EMI Amount: ₹{service.emiAmount}</p>
                  <p>Due Date: {formatDate(service.dueDate)}</p>
                </div>

                {/* ✅ Mark as Paid button for pending services */}
                {service.status === "pending" && (
                  <button
                    onClick={() => checkServicePayment(index)}
                    className="absolute bottom-4 right-4 px-3 py-1 bg-green-600 text-white rounded hover:bg-green-700 transition text-sm"
                  >
                    Mark as Paid
                  </button>
                )}
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}
